changeSet.sql:
UPDATE magic.spell_24
SET name = jsonb_strip_nulls(
        (name - 'ru' - 'en')
        || jsonb_build_object(
                'rus', COALESCE(name ->> 'rus', name ->> 'ru'),
                'eng', COALESCE(name ->> 'eng', name ->> 'en')
           )
           )
WHERE jsonb_exists(name, 'ru') OR jsonb_exists(name, 'en');

UPDATE magic.spell_24_ai
SET name = jsonb_strip_nulls(
        (name - 'ru' - 'en')
        || jsonb_build_object(
                'rus', COALESCE(name ->> 'rus', name ->> 'ru'),
                'eng', COALESCE(name ->> 'eng', name ->> 'en')
           )
           )
WHERE jsonb_exists(name, 'ru') OR jsonb_exists(name, 'en');

UPDATE magic.spell_24_ai
SET alias_name = jsonb_strip_nulls(
        (alias_name - 'ru' - 'en')
        || jsonb_build_object(
                'rus', COALESCE(alias_name ->> 'rus', alias_name ->> 'ru'),
                'eng', COALESCE(alias_name ->> 'eng', alias_name ->> 'en')
           )
           )
WHERE alias_name IS NOT NULL
  AND (jsonb_exists(alias_name, 'ru') OR jsonb_exists(alias_name, 'en'));
